            if os.path.isfile(mackup_filepath) or os.path.isdir(mackup_filepath):
                if os.path.exists(home_filepath):
                    if self.verbose:
                        print(
                            "Reverting {}\n  at {} ...".format(
                                mackup_filepath, home_filepath
                            )
                        )
